//! OCEL event-type emission surface for `wasm4pm-compat`.
//!
//! Generated by `wasm4pm-compat-pack` from EventType individuals in the
//! pack ontology. Emission only: ggen emits `OCELEvent` values; discovery,
//! conformance, fitness, and variants belong to `wasm4pm-compat`.
//!
//! Exactly 3 EventType individuals exist in the
//! ontology as of this render (`event_count` SPARQL, independent of the
//! `event_types` query that drives the enum/emit-fn bodies below).

use chrono::{DateTime, FixedOffset};
use wasm4pm_compat::ocel::{OCELAttributeValue, OCELEvent, OCELEventAttribute, OCELRelationship};

/// Total count of `w4pm:EventType` individuals, per the independent
/// `event_count` SPARQL query above -- used by the generated proof suite
/// as a self-updating cardinality oracle instead of a hand-transcribed
/// literal.
pub const EVENT_TYPE_COUNT: usize = 3;

/// Every OCEL event type this generator emits.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EmittedEventType {
    /// `graph_union_hashed` — binds a `OntologyGraph` object.
    GraphUnionHashed,
    /// `pack_lock_verified` — binds a `Pack` object.
    PackLockVerified,
    /// `receipt_chained` — binds a `SyncReceipt` object.
    ReceiptChained,
}

impl EmittedEventType {
    /// OCEL 2.0 event-type name, as it appears in the log's `eventTypes`.
    pub fn name(self) -> &'static str {
        match self {
            Self::GraphUnionHashed => "graph_union_hashed",
            Self::PackLockVerified => "pack_lock_verified",
            Self::ReceiptChained => "receipt_chained",
        }
    }
}


/// Emit a `graph_union_hashed` event related to one `OntologyGraph` object.
///
/// Caller supplies `time` (no wall-clock reads inside the emission surface)
/// and one `String` value per ontology-declared attribute below, in the
/// same order `w4pm:hasAttribute`/`w4pm:attrName` list them.
pub fn emit_graph_union_hashed(
    id: String,
    time: DateTime<FixedOffset>,
    ontology_graph_id: String,
    graph_hash: String,
) -> OCELEvent {
    debug_assert!(!id.is_empty(), "w4pm:requiresNonEmptyId: `graph_union_hashed` event id must not be empty");
    debug_assert!(!graph_hash.is_empty(), "w4pm:requiresNonEmpty: `graph_union_hashed`'s `graph_hash` attribute must not be empty");
    OCELEvent {
        id,
        event_type: "graph_union_hashed".to_string(),
        time,
        attributes: vec![
            OCELEventAttribute {
                name: "graph_hash".to_string(),
                value: OCELAttributeValue::String(graph_hash),
            },
        ],
        relationships: vec![OCELRelationship {
            object_id: ontology_graph_id,
            qualifier: "OntologyGraph".to_string(),
        }],
    }
}

